import { isString } from 'lodash-es';
import { type PropsWithChildren } from 'react';

import { symbolAtom } from './styles.sty.js';

/**
 * @internal
 **/
export const SymbolAtom = ({ children, ...rest }: PropsWithChildren) => {
  return !isString(children) ? (
    <div className={symbolAtom} {...rest}>
      {children}
    </div>
  ) : null;
};

SymbolAtom['displayName'] = 'SymbolAtom';
